import { z } from "zod";

// Strict schema — rejects anything not explicitly allowed
const CreateUserSchema = z.object({
  username: z.string()
    .min(3).max(30)
    .regex(/^[a-zA-Z0-9_-]+$/, "Only alphanumeric, underscore, hyphen"),
  email: z.string().email().max(254),
