            if let hit = raycastAtLocation(location) {
                beginSelection(nodeId: hit.nodeId)
            }

        case .changed:
            // Update manipulation
            updateSelection(location: location)

        case .ended:
            // Commit action
            if let selectedNode = currentSelection {
                delegate?.didSelectNode(selectedNode)
            }
        }
    }
}
